mapper.select:
select

from dish_ingredient di
left join dish_ingredient_category c2 on di.category_id = c2.id
left join dish_ingredient_category c1 on c2.parent_id = c1.id


        and di.name like concat('%',#{criteria.name},'%')


        and di.category = #{criteria.category}


        and di.category_id = #{criteria.categoryId}


        and c2.parent_id = #{criteria.parentCategoryId}


        and di.enabled = #{criteria.enabled}


order by di.id desc
